// Landing.jsx - White theme like AI SaaS landing
import React, { useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { LogoFull, LogoMark } from '../components/Logo';
import s from './Landing.module.css';

const FEATURES = [
  { icon: '🎯', title: 'AI-Powered Analytics', desc: 'Analyze campaign performance trends across KPIs with intelligent insights.' },
  { icon: '⚡', title: 'Smart Automation', desc: 'Create, assign, and automate tasks with intelligent AI workflows.' },
  { icon: '📊', title: 'Forecast & Predict', desc: 'Forecast LTV, retention, and ROAS for specific segments.' },
  { icon: '🔍', title: 'Budget Optimization', desc: 'Recommend budget reallocations and targeting changes automatically.' },
];

const DEMO = [
  { user: "Which of my campaigns had the best ROI?", bot: "Based on last 30 days, 'Summer Launch' campaign showed 42% ROI, outperforming others by 18%." },
  { user: "Compare retention across iOS and Android", bot: "iOS retention is 68% vs Android at 54% at Day 7. Android users show 12% higher drop-off." },
];

export default function Landing() {
  const nav = useNavigate();
  const { user } = useAuth();

  useEffect(() => {
    const io = new IntersectionObserver(entries => entries.forEach(e => e.isIntersecting && e.target.classList.add(s.vis)), { threshold: 0.1 });
    document.querySelectorAll(`.${s.fade}`).forEach(el => io.observe(el));
    return () => io.disconnect();
  }, []);

  return (
    <div className={s.page}>
      <div className={s.glow1} /><div className={s.glow2} />
      <nav className={s.nav}>
        <LogoFull size={34} />
        <div className={s.navLinks}><a href="#features">Features</a><a href="#pipeline">Pipeline</a><a href="#demo">Demo</a></div>
        <div className={s.navActions}>
          {user ? <button className={s.btnPrimary} onClick={() => nav('/chat')}>Open Chat →</button> : (<><button className={s.btnGhost} onClick={() => nav('/login')}>Login</button><button className={s.btnPrimary} onClick={() => nav('/register')}>Start Free →</button></>)}
        </div>
      </nav>
      <section className={s.hero}>
        <div className={s.heroLeft}>
          <div className={s.badge}><span className={s.badgeDot} />AI-Powered Analytics Platform</div>
          <h1 className={s.heroTitle}>Design Smarter with<br /><span className={s.hiGradient}>AI Precision</span></h1>
          <p className={s.heroSub}>Streamline your workflow and eliminate repetitive tasks with intelligent automation. Let our AI help you analyze data and act faster with unmatched precision.</p>
          <div className={s.heroCta}>
            <button className={s.btnHero} onClick={() => nav(user ? '/chat' : '/register')}>Start for free →</button>
            <button className={s.btnHeroOutline} onClick={() => nav('/login')}>Sign in</button>
          </div>
          <div className={s.heroStats}>
            {[['10K+', 'Users'], ['99.9%', 'Uptime'], ['<100ms', 'Latency'], ['24/7', 'Support']].map(([n, l], i) => (<div key={i} className={s.statItem}><span className={s.statNum}>{n}</span><span className={s.statLbl}>{l}</span></div>))}
          </div>
        </div>
        <div className={s.heroRight}>
          <div className={s.chatCard}>
            <div className={s.chatCardHeader}><LogoMark size={24} /><span className={s.chatCardTitle}>AI Advisor</span><div className={s.onlineDot} /><span className={s.onlineTxt}>Active</span></div>
            <div className={s.chatMessages}>{DEMO.map((d, i) => (<div key={i} className={s.chatPair}><div className={s.userBubble}>{d.user}</div><div className={s.botBubble}><LogoMark size={20} /><span>{d.bot}</span></div></div>))}</div>
            <div className={s.chatInputFake}><span>Ask anything about your campaigns...</span><div className={s.sendFake} /></div>
          </div>
        </div>
      </section>
      <section className={s.section} id="features">
        <div className={`${s.fade} ${s.eyebrow}`}><div className={s.line} />Capabilities</div>
        <h2 className={`${s.fade} ${s.secTitle}`}>Powerful Features Built for Efficiency</h2>
        <p className={`${s.fade} ${s.secSub}`}>From automation to analytics, our AI platform helps you simplify complex workflows and accelerate growth.</p>
        <div className={s.featureGrid}>{FEATURES.map((f, i) => (<div key={i} className={`${s.fade} ${s.featureCard}`}><div className={s.featIcon}>{f.icon}</div><div className={s.featTitle}>{f.title}</div><div className={s.featDesc}>{f.desc}</div></div>))}</div>
      </section>
      <section className={s.section} id="pipeline">
        <div className={`${s.fade} ${s.eyebrow}`}><div className={s.line} />Architecture</div>
        <h2 className={`${s.fade} ${s.secTitle}`}>Intelligent Pipeline</h2>
        <div className={`${s.fade} ${s.pipelineWrap}`}>
          {[['01', 'Data Ingestion', 'Collect & validate'], ['02', 'Processing', 'Clean & normalize'], ['03', 'Analysis', 'AI/ML models'], ['04', 'Insights', 'Pattern detection'], ['05', 'Generation', 'LLM response'], ['06', 'Delivery', 'Actionable output']].map(([n, lbl, desc], i) => (<div key={i} className={s.pipeStep}><div className={s.pipeNum}>{n}</div><div className={s.pipeLbl}>{lbl}</div><div className={s.pipeDesc}>{desc}</div></div>))}
        </div>
      </section>
      <section className={s.ctaSection}>
        <h2 className={`${s.fade} ${s.ctaTitle}`}>Ready to upgrade your workflow?</h2>
        <p className={`${s.fade} ${s.ctaSub}`}>Join thousands of teams using AI to work smarter, not harder.</p>
        <button className={`${s.fade} ${s.btnHero}`} onClick={() => nav(user ? '/chat' : '/register')}>Start free →</button>
      </section>
      <footer className={s.footer}>
        <LogoFull size={28} />
        <p className={s.footerTxt}>© 2025 AWAL GPT · AI-powered Tamazight Assistant</p>
      </footer>
    </div>
